--
-- Create foreign key
--
ALTER TABLE proveedores
ADD CONSTRAINT fk_proveedores_tipo_documento_identidad FOREIGN KEY (id_tipo_documento_identidad)
REFERENCES tipo_documento_identidad (id) ON DELETE NO ACTION ON UPDATE NO ACTION;

DELIMITER $$

--
-- Create procedure `sp_updateProveedor`
--
CREATE

PROCEDURE sp_updateProveedor (IN p_id int,
IN p_id_tipo_documento_identidad int,
IN p_numero_documento varchar(20),
IN p_nombres_apellidos varchar(200),
IN p_direccion varchar(255),
IN p_codigo_ubigeo varchar(10),
IN p_email varchar(100),
IN p_telefono varchar(20),
IN p_estado enum ('Activado', 'Desactivado'))
BEGIN
  UPDATE `proveedores`
  SET id_tipo_documento_identidad = p_id_tipo_documento_identidad,
      numero_documento = p_numero_documento,
      nombres_apellidos = p_nombres_apellidos,
      direccion = p_direccion,
      codigo_ubigeo = p_codigo_ubigeo,
      email = p_email,
      telefono = p_telefono,
      estado = p_estado
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_getOneProveedor`
--
CREATE

PROCEDURE sp_getOneProveedor (IN p_id int)
BEGIN
  SELECT
    id,
    id_tipo_documento_identidad,
    numero_documento,
    nombres_apellidos,
    direccion,
    codigo_ubigeo,
    email,
    telefono,
    estado
  FROM `proveedores`
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_getAllProveedores`
--
CREATE

PROCEDURE sp_getAllProveedores ()
BEGIN
  SELECT
    p.id,
    p.id_tipo_documento_identidad,
    tdi.nombre AS tipo_documento_nombre,
    p.numero_documento,
    p.nombres_apellidos,
    p.direccion,
    p.email,
    p.telefono,
    p.estado
  FROM `proveedores` p
    JOIN `tipo_documento_identidad` tdi
      ON p.id_tipo_documento_identidad = tdi.id
  ORDER BY p.nombres_apellidos ASC;
END
$$

--
-- Create procedure `sp_deleteProveedor`
--
CREATE

PROCEDURE sp_deleteProveedor (IN p_id int)
BEGIN
  UPDATE `proveedores`
  SET estado = 'Desactivado'
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_createProveedor`
--
CREATE

PROCEDURE sp_createProveedor (IN p_id_tipo_documento_identidad int,
IN p_numero_documento varchar(20),
IN p_nombres_apellidos varchar(200),
IN p_direccion varchar(255),
IN p_codigo_ubigeo varchar(10),
IN p_email varchar(100),
IN p_telefono varchar(20))
BEGIN
  INSERT INTO `proveedores` (id_tipo_documento_identidad, numero_documento, nombres_apellidos, direccion, codigo_ubigeo, email, telefono)
    VALUES (p_id_tipo_documento_identidad, p_numero_documento, p_nombres_apellidos, p_direccion, p_codigo_ubigeo, p_email, p_telefono);
  SELECT
    LAST_INSERT_ID() AS id;
END
$$

