PROCEDURE sp_updateCliente (IN p_id int,
IN p_id_tipo_documento_identidad int,
IN p_numero_documento varchar(20),
IN p_nombres_apellidos varchar(200),
IN p_direccion varchar(255),
IN p_codigo_ubigeo varchar(10),
IN p_email varchar(100),
IN p_telefono varchar(20),
IN p_estado enum ('Activado', 'Desactivado'))
BEGIN
  UPDATE clientes
  SET id_tipo_documento_identidad = p_id_tipo_documento_identidad,
      numero_documento = p_numero_documento,
      nombres_apellidos = p_nombres_apellidos,
      direccion = p_direccion,
      codigo_ubigeo = p_codigo_ubigeo,
      email = p_email,
      telefono = p_telefono,
      estado = p_estado
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_searchClientes`
--
CREATE

PROCEDURE sp_searchClientes (IN p_search_term varchar(200))
BEGIN
  SELECT
    c.id,
    c.id_tipo_documento_identidad,
    tdi.nombre AS tipo_documento_nombre,
    c.numero_documento,
    c.nombres_apellidos,
    c.direccion,
    c.codigo_ubigeo,
    c.email,
    c.telefono
  FROM clientes c
    JOIN tipo_documento_identidad tdi
      ON c.id_tipo_documento_identidad = tdi.id
  WHERE (c.nombres_apellidos LIKE p_search_term
  OR c.numero_documento LIKE p_search_term)
  AND c.estado = 'Activado'
  ORDER BY c.nombres_apellidos;
END
$$

--
-- Create procedure `sp_getOneCliente`
--
CREATE

PROCEDURE sp_getOneCliente (IN p_id int)
BEGIN
  SELECT
    id,
    id_tipo_documento_identidad,
    numero_documento,
    nombres_apellidos,
    direccion,
    codigo_ubigeo,
    email,
    telefono,
    estado
  FROM clientes
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_getAllClientes`
--
CREATE

PROCEDURE sp_getAllClientes ()
BEGIN
  SELECT
    c.id,
    c.id_tipo_documento_identidad,
    tdi.nombre AS tipo_documento_nombre,
    c.numero_documento,
    c.nombres_apellidos,
    c.direccion,
    c.codigo_ubigeo,
    c.email,
    c.telefono,
    c.estado
  FROM clientes c
    JOIN tipo_documento_identidad tdi
      ON c.id_tipo_documento_identidad = tdi.id
  ORDER BY c.nombres_apellidos;
END
$$

--
-- Create procedure `sp_deleteCliente`
--
CREATE

PROCEDURE sp_deleteCliente (IN p_id int)
BEGIN
  DELETE
    FROM clientes
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_createCliente`
--
CREATE

PROCEDURE sp_createCliente (IN p_id_tipo_documento_identidad int,
IN p_numero_documento varchar(20),
IN p_nombres_apellidos varchar(200),
IN p_direccion varchar(255),
IN p_codigo_ubigeo varchar(10),
IN p_email varchar(100),
IN p_telefono varchar(20))
BEGIN
  INSERT INTO clientes (id_tipo_documento_identidad,
  numero_documento,
  nombres_apellidos,
  direccion,
  codigo_ubigeo,
  email,
  telefono)
    VALUES (
    p_id_tipo_documento_identidad,
    p_numero_documento,
    p_nombres_apellidos,
    p_direccion,
    p_codigo_ubigeo,
    p_email,
    p_telefono
    );
  SELECT
    LAST_INSERT_ID() AS id;
END
$$

