--
-- Create procedure `sp_updateUser`
--
CREATE

PROCEDURE sp_updateUser (IN p_id int, IN p_nombre_completo varchar(100), IN p_email varchar(100), IN p_id_rol int, IN p_activo boolean, IN p_password_hash varchar(255))
BEGIN
  UPDATE usuarios
  SET nombre_completo = p_nombre_completo,
      email = p_email,
      id_rol = p_id_rol,
      activo = p_activo
  WHERE id = p_id;

  IF p_password_hash IS NOT NULL THEN
    UPDATE usuarios
    SET password_hash = p_password_hash
    WHERE id = p_id;
  END IF;
END
$$

--
-- Create procedure `sp_readOneUser`
--
CREATE

PROCEDURE sp_readOneUser (IN p_id int)
BEGIN
  SELECT
    id,
    username,
    nombre_completo,
    email,
    id_rol,
    activo
  FROM usuarios
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_getUsersByRole`
--
CREATE

PROCEDURE sp_getUsersByRole (IN p_role_name varchar(50))
BEGIN
  SELECT
    u.id,
    u.username,
    u.nombre_completo,
    u.email
  FROM usuarios u
    JOIN roles r
      ON u.id_rol = r.id
  WHERE r.nombre_rol = p_role_name
  AND u.activo = 1
  ORDER BY u.nombre_completo;
END
$$

--
-- Create procedure `sp_getUserByUsername`
--
CREATE

PROCEDURE sp_getUserByUsername (IN p_username varchar(50))
BEGIN
  SELECT
    u.id,
    u.username,
    u.nombre_completo,
    u.email,
    u.password_hash,
    u.id_rol,
    r.nombre_rol
  FROM usuarios u
    JOIN roles r
      ON u.id_rol = r.id
  WHERE u.username = p_username;
END
$$

--
-- Create procedure `sp_getAllUsers`
--
CREATE

PROCEDURE sp_getAllUsers ()
BEGIN
  SELECT
    u.id,
    u.username,
    u.nombre_completo,
    u.email,
    u.id_rol,
    r.nombre_rol,
    u.activo
  FROM usuarios u
    JOIN roles r
      ON u.id_rol = r.id
  ORDER BY u.nombre_completo;
END
$$

--
-- Create procedure `sp_deleteUser`
--
CREATE

PROCEDURE sp_deleteUser (IN p_id int)
BEGIN
  UPDATE usuarios
  SET activo = 0
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_createUser`
--
CREATE

PROCEDURE sp_createUser (IN p_username varchar(50), IN p_nombre_completo varchar(100), IN p_email varchar(100), IN p_password_hash varchar(255), IN p_id_rol int)
BEGIN
  INSERT INTO usuarios (username, nombre_completo, email, password_hash, id_rol)
    VALUES (p_username, p_nombre_completo, p_email, p_password_hash, p_id_rol);
END
$$

