--
-- Create table `tipo_movimiento`
--
CREATE TABLE tipo_movimiento (
  id int(11) NOT NULL AUTO_INCREMENT,
  tipo char(1) NOT NULL COMMENT 'E: Entrada, S: Salida',
  codigo char(3) NOT NULL,
  descripcion varchar(1000) NOT NULL,
  estado enum ('activado', 'desactivado') NOT NULL DEFAULT 'activado',
  fecha_creacion datetime NOT NULL DEFAULT CURRENT_TIMESTAMP(),
  fecha_modificacion datetime NOT NULL DEFAULT CURRENT_TIMESTAMP() ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id)
)
ENGINE = INNODB,
AUTO_INCREMENT = 6,
AVG_ROW_LENGTH = 3276,
CHARACTER SET utf8mb4,
COLLATE utf8mb4_unicode_ci,
ROW_FORMAT = DYNAMIC;

--
-- Create index `codigo_UNIQUE` on table `tipo_movimiento`
--
ALTER TABLE tipo_movimiento
ADD UNIQUE INDEX codigo_UNIQUE (codigo);

DELIMITER $$

--
-- Create procedure `sp_verificarAperturaActiva`
--
CREATE

PROCEDURE sp_verificarAperturaActiva (IN p_fecha date)
BEGIN
  DECLARE v_apertura_count int;
  DECLARE v_cierre_count int;

  -- Contar las aperturas para la fecha dada
  SELECT
    COUNT(*) INTO v_apertura_count
  FROM apertura_cierre_caja
  WHERE fecha_movimiento = p_fecha
  AND tipo_movimiento = 'Apertura';

  -- Contar los cierres para la fecha dada
  SELECT
    COUNT(*) INTO v_cierre_count
  FROM apertura_cierre_caja
  WHERE fecha_movimiento = p_fecha
  AND tipo_movimiento = 'Cierre';

  -- Determinar si la caja está activa y devolver el resultado
  IF v_apertura_count > 0
    AND v_cierre_count = 0 THEN
    SELECT
      1 AS activa;
  ELSE
    SELECT
      0 AS activa;
  END IF;
END
$$

--
-- Create procedure `sp_verificar_cierre_por_fecha`
--
CREATE

PROCEDURE sp_verificar_cierre_por_fecha (IN p_fecha date)
BEGIN
  DECLARE cierre_existente int DEFAULT 0;

  SELECT
    COUNT(*) INTO cierre_existente
  FROM apertura_cierre_caja
  WHERE fecha_movimiento = p_fecha
  AND tipo_movimiento = 'cierre';

  SELECT
    cierre_existente AS cierre_existente;
END
$$

--
-- Create procedure `sp_updateTipoMovimiento`
--
CREATE

PROCEDURE sp_updateTipoMovimiento (IN p_id int,
IN p_tipo char(1),
IN p_codigo char(3),
IN p_descripcion varchar(1000),
IN p_estado enum ('activado', 'desactivado'))
BEGIN
  UPDATE tipo_movimiento
  SET tipo = p_tipo,
      codigo = p_codigo,
      descripcion = p_descripcion,
      estado = p_estado
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_getOneTipoMovimiento`
--
CREATE

PROCEDURE sp_getOneTipoMovimiento (IN p_id int)
BEGIN
  SELECT
    id,
    tipo,
    codigo,
    descripcion,
    estado
  FROM tipo_movimiento
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_getAllTiposMovimiento`
--
CREATE

PROCEDURE sp_getAllTiposMovimiento (IN p_descripcion varchar(255),
IN p_estado varchar(20))
BEGIN
  SELECT
    id,
    tipo,
    codigo,
    descripcion,
    estado,
    fecha_creacion,
    fecha_modificacion
  FROM tipo_movimiento
  WHERE (p_descripcion IS NULL
  OR p_descripcion = ''
  OR descripcion LIKE CONCAT('%', p_descripcion COLLATE utf8mb4_unicode_ci, '%'))
  AND (p_estado IS NULL
  OR p_estado = ''
  OR estado COLLATE utf8mb4_unicode_ci = p_estado COLLATE utf8mb4_unicode_ci);
END
$$

--
-- Create procedure `sp_deleteTipoMovimiento`
--
CREATE

PROCEDURE sp_deleteTipoMovimiento (IN p_id int)
BEGIN
  UPDATE tipo_movimiento
  SET estado = 'desactivado'
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_createTipoMovimiento`
--
CREATE

PROCEDURE sp_createTipoMovimiento (IN p_tipo char(1),
IN p_codigo char(3),
IN p_descripcion varchar(1000))
BEGIN
  INSERT INTO tipo_movimiento (tipo, codigo, descripcion)
    VALUES (p_tipo, p_codigo, p_descripcion);
  SELECT
    LAST_INSERT_ID() AS id;
END
$$

