--
-- Create table `almacenes`
--
CREATE TABLE almacenes (
  id int(11) NOT NULL AUTO_INCREMENT,
  nombre varchar(255) NOT NULL,
  estado tinyint(1) NOT NULL DEFAULT 1,
  fecha_creacion timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP(),
  fecha_actualizacion timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP() ON UPDATE CURRENT_TIMESTAMP,
  fecha_eliminacion datetime DEFAULT NULL,
  predeterminado tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Indica si el almacén es el predeterminado',
  PRIMARY KEY (id)
)
ENGINE = INNODB,
AUTO_INCREMENT = 3,
AVG_ROW_LENGTH = 8192,
CHARACTER SET utf8mb4,
COLLATE utf8mb4_unicode_ci,
ROW_FORMAT = DYNAMIC;

DELIMITER $$

--
-- Create procedure `sp_leer_almacenes`
--
CREATE

PROCEDURE sp_leer_almacenes (IN p_nombre varchar(255),
IN p_estado boolean,
IN p_offset int,
IN p_limit int)
BEGIN
  SELECT
    id,
    nombre,
    estado,
    predeterminado,
    fecha_creacion,
    fecha_eliminacion
  FROM `almacenes`
  WHERE (p_nombre IS NULL
  OR p_nombre = ''
  OR nombre LIKE CONCAT('%', p_nombre, '%') COLLATE utf8mb4_unicode_ci)
  AND (p_estado IS NULL
  OR estado = p_estado)
  ORDER BY id DESC;
END
$$

--
-- Create procedure `sp_leer_almacen_por_id`
--
CREATE

PROCEDURE sp_leer_almacen_por_id (IN p_id int)
BEGIN
  SELECT
    id,
    nombre,
    estado,
    predeterminado
  FROM `almacenes`
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_desactivar_almacen`
--
CREATE

PROCEDURE sp_desactivar_almacen (IN p_id int)
BEGIN
  UPDATE `almacenes`
  SET estado = FALSE,
      fecha_eliminacion = NOW()
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_crear_almacen`
--
CREATE

PROCEDURE sp_crear_almacen (IN p_nombre varchar(255),
IN p_predeterminado boolean)
BEGIN
  -- Si se va a establecer como predeterminado, desmarcar cualquier otro
  IF p_predeterminado = 1 THEN
    UPDATE `almacenes`
    SET `predeterminado` = 0;
  END IF;

  INSERT INTO `almacenes` (nombre, predeterminado, estado)
    VALUES (p_nombre, p_predeterminado, 1);

  SELECT
    LAST_INSERT_ID() AS id;
END
$$

--
-- Create procedure `sp_contar_almacenes`
--
CREATE

PROCEDURE sp_contar_almacenes (IN p_nombre varchar(255),
IN p_estado boolean)
BEGIN
  SELECT
    COUNT(id) AS total
  FROM `almacenes`
  WHERE (p_nombre IS NULL
  OR p_nombre = ''
  OR nombre LIKE CONCAT('%', p_nombre, '%') COLLATE utf8mb4_unicode_ci)
  AND (p_estado IS NULL
  OR estado = p_estado);
END
$$

--
-- Create procedure `sp_actualizar_almacen`
--
CREATE

PROCEDURE sp_actualizar_almacen (IN p_id int,
IN p_nombre varchar(255),
IN p_estado boolean,
IN p_predeterminado boolean)
BEGIN
  -- Si se va a establecer como predeterminado, desmarcar cualquier otro
  IF p_predeterminado = 1 THEN
    UPDATE `almacenes`
    SET `predeterminado` = 0
    WHERE id != p_id;
  END IF;

  UPDATE `almacenes`
  SET nombre = p_nombre,
      estado = p_estado,
      predeterminado = p_predeterminado
  WHERE id = p_id;
END
$$

DELIMITER ;

