--
-- Create procedure `sp_readOneReservation`
--
CREATE

PROCEDURE sp_readOneReservation (IN p_id int)
BEGIN
  SELECT
    id,
    id_mesa,
    nombre_cliente,
    telefono_cliente,
    email_cliente,
