--
-- Create procedure `sp_updateOrderStatus`
--
CREATE

PROCEDURE sp_updateOrderStatus (IN p_id_pedido int,
IN p_estado varchar(50))
BEGIN
  -- Actualiza solo el estado del pedido
  UPDATE pedidos
  SET estado = p_estado
  WHERE id = p_id_pedido;

  -- Si el estado es 'completado', también actualiza el estado de la mesa a 'disponible'.
  -- Asumiendo que un pedido completado libera la mesa.
  IF p_estado = 'completado'
    OR p_estado = 'cancelado' THEN
    UPDATE mesas
    SET estado = 'disponible'
    WHERE id = (SELECT
        id_mesa
      FROM pedidos
      WHERE id = p_id_pedido);
  END IF;
END
$$

--
-- Create procedure `sp_getOrdersByStatus`
--
CREATE

PROCEDURE sp_getOrdersByStatus (IN p_status varchar(255))
BEGIN
  SELECT
    p.id,
    p.id_mesa,
    m.numero_mesa,
    p.id_usuario_mozo,
    u.nombre_completo AS nombre_mozo,
    p.estado,
    p.total,
    p.fecha_creacion
  FROM pedidos p
    LEFT JOIN mesas m
      ON p.id_mesa = m.id
    LEFT JOIN usuarios u
      ON p.id_usuario_mozo = u.id
  WHERE FIND_IN_SET(p.estado, p_status)
  ORDER BY p.fecha_creacion DESC;
END
$$

--
-- Create procedure `sp_getOrderDetail`
--
CREATE

PROCEDURE sp_getOrderDetail (IN p_id_pedido int)
BEGIN
  SELECT
    p.id,
    p.id_mesa,
    m.numero_mesa,
    p.id_usuario_mozo,
    u.nombre_completo AS nombre_mozo,
    p.estado,
    p.total,
    p.fecha_creacion,
    p.fecha_actualizacion,
    p.id_cliente,
    p.id_tipo_documento_venta,
    p.id_serie_documento,
    p.numero_documento,
    c.nombres_apellidos AS nombre_cliente,
    c.numero_documento AS ruc_cliente,
    c.id_tipo_documento_identidad AS id_tipo_documento_identidad_cliente,
    c.direccion AS direccion_cliente,
    c.codigo_ubigeo
  FROM pedidos p
    LEFT JOIN mesas m
      ON p.id_mesa = m.id
    LEFT JOIN usuarios u
      ON p.id_usuario_mozo = u.id
    LEFT JOIN clientes c
      ON p.id_cliente = c.id
  WHERE p.id = p_id_pedido;
END
$$

--
-- Create procedure `sp_getAvailableTables`
--
CREATE

PROCEDURE sp_getAvailableTables ()
BEGIN
  SELECT
    m.id,
    m.numero_mesa,
    m.capacidad,
    m.estado,
    m.es_libre
  FROM mesas m
  WHERE m.id NOT IN (SELECT
      p.id_mesa
    FROM pedidos p
    WHERE p.estado = 'abierto');
END
$$

--
-- Create procedure `sp_getAllOrders`
--
CREATE

PROCEDURE sp_getAllOrders (IN p_status varchar(255))
BEGIN
  SELECT
    p.id,
    p.id_mesa,
    m.numero_mesa,
    p.id_usuario_mozo,
    u.nombre_completo AS nombre_mozo,
    p.estado,
    p.total,
    p.fecha_creacion
  FROM pedidos p
    LEFT JOIN mesas m
      ON p.id_mesa = m.id
    LEFT JOIN usuarios u
      ON p.id_usuario_mozo = u.id
  WHERE (p_status IS NULL
  OR p_status = ''
  OR FIND_IN_SET(p.estado, p_status))
  ORDER BY p.fecha_creacion DESC;
END
$$

