--
-- Create procedure `sp_leer_ventas`
--
CREATE

PROCEDURE sp_leer_ventas (IN p_fecha_inicio date,
IN p_fecha_fin date,
IN p_estado varchar(20),
IN p_id_tipo_documento int,
IN p_search varchar(100),
IN p_page int,
IN p_limit int)
BEGIN
  DECLARE v_offset int;
  SET v_offset = (p_page - 1) * p_limit;

  SELECT
    v.id,
    v.id_pedido, -- <--- Columna añadida
    v.fecha_emision,
    c.nombres_apellidos AS nombre_cliente,
    tdv.descripcion,
    sd.serie,
    v.numero_documento,
    V.porcentaje,
    v.base,
    v.impuesto,
    v.total,
    v.estado
  FROM ventas v
    LEFT JOIN clientes c
      ON v.id_cliente = c.id
    LEFT JOIN tipo_documento_venta tdv
      ON v.id_tipo_documento_venta = tdv.id
    LEFT JOIN series_documentos sd
      ON v.id_serie_documento = sd.id
  -- LEFT JOIN impuestos i ON v.id_impuesto = i.id
  WHERE (p_fecha_inicio IS NULL
  OR v.fecha_emision >= p_fecha_inicio)
  AND (p_fecha_fin IS NULL
  OR v.fecha_emision <= p_fecha_fin)
  AND (p_estado = 'Todos'
  OR v.estado = p_estado)
  AND (p_id_tipo_documento IS NULL
  OR v.id_tipo_documento_venta = p_id_tipo_documento)
  AND (p_search IS NULL
  OR COALESCE(c.nombres_apellidos) LIKE CONCAT('%', p_search COLLATE utf8mb4_unicode_ci, '%')
  OR COALESCE(v.numero_documento) LIKE CONCAT('%', p_search COLLATE utf8mb4_unicode_ci, '%')

  )

  -- OR COALESCE(c.nombres_apellidos, prov.nombres_apellidos) LIKE CONCAT('%', p_filter COLLATE utf8mb4_unicode_ci, '%')



  ORDER BY v.fecha_emision DESC, v.id DESC
  LIMIT v_offset, p_limit;
END
$$

--
-- Create procedure `sp_contar_ventas`
--
CREATE

PROCEDURE sp_contar_ventas (IN p_fecha_inicio date,
IN p_fecha_fin date,
IN p_estado varchar(10),
IN p_id_tipo_documento int,
IN p_search varchar(100))
BEGIN
  SELECT
    COUNT(v.id) AS total
  FROM ventas v
    LEFT JOIN clientes c
      ON v.id_cliente = c.id
    JOIN tipo_documento_venta tdv
      ON v.id_tipo_documento_venta = tdv.id
    JOIN series_documentos s
      ON v.id_serie_documento = s.id
  WHERE (p_fecha_inicio IS NULL
  OR v.fecha_emision >= p_fecha_inicio)
  AND (p_fecha_fin IS NULL
  OR v.fecha_emision <= p_fecha_fin)
  AND (p_estado IS NULL
  OR p_estado = 'Todos'
  OR v.estado COLLATE utf8mb4_unicode_ci = p_estado)
  AND (p_id_tipo_documento IS NULL
  OR v.id_tipo_documento_venta = p_id_tipo_documento)
  AND (p_search IS NULL
  OR c.nombres_apellidos COLLATE utf8mb4_unicode_ci LIKE CONCAT('%', p_search, '%')
  OR v.numero_documento COLLATE utf8mb4_unicode_ci LIKE CONCAT('%', p_search, '%'));
END
$$

--
-- Create procedure `sp_calcular_cierre`
--
CREATE

PROCEDURE sp_calcular_cierre (IN p_fecha date)
BEGIN
  DECLARE total_movimientos decimal(10, 2);
  DECLARE total_ventas decimal(10, 2);
  DECLARE total_cierre decimal(10, 2);

  -- Calcular el total de movimientos de caja para la fecha dada
  SELECT
    COALESCE(SUM(CASE WHEN tipo_movimiento = 'ENTRADA' THEN importe ELSE 0 END) -
    SUM(CASE WHEN tipo_movimiento = 'SALIDA' THEN importe ELSE 0 END), 0) INTO total_movimientos
  FROM movimientos_caja
  WHERE DATE(fecha) = p_fecha;

  -- Calcular el total de ventas emitidas para la fecha dada
  SELECT
    COALESCE(SUM(total), 0) INTO total_ventas
  FROM ventas
  WHERE DATE(fecha_emision) = p_fecha
  AND estado = 'Emitida';

  -- Calcular el total de cierre
  SET total_cierre = total_movimientos + total_ventas;

  -- Devolver el resultado
  SELECT
    total_cierre AS total_cierre;

END
$$

