  fecha_movimiento date NOT NULL,
  id_tipo_documento_venta int(11) DEFAULT NULL,
  serie_documento varchar(10) DEFAULT NULL,
  numero_documento varchar(20) DEFAULT NULL,
  tipo_entidad enum ('C', 'P') DEFAULT NULL COMMENT 'C: Cliente, P: Proveedor',
  id_cliente int(11) DEFAULT NULL,
  id_proveedor int(11) DEFAULT NULL,
  estado enum ('Activado', 'Desactivado') NOT NULL DEFAULT 'Activado',
  fecha_creacion datetime DEFAULT CURRENT_TIMESTAMP(),
  fecha_modificacion datetime DEFAULT CURRENT_TIMESTAMP() ON UPDATE CURRENT_TIMESTAMP,
  id_almacen int(11) DEFAULT NULL,
  id_pedido int(11) DEFAULT NULL,
  PRIMARY KEY (id)
)
ENGINE = INNODB,
AUTO_INCREMENT = 5,
AVG_ROW_LENGTH = 8192,
CHARACTER SET utf8mb4,
COLLATE utf8mb4_unicode_ci,
ROW_FORMAT = DYNAMIC;

