--
-- Create procedure `sp_readOneProduct`
--
CREATE

PROCEDURE sp_readOneProduct (IN p_id int)
BEGIN
  SELECT
    p.id,
    p.nombre,
    p.descripcion,
    p.precio,
    p.id_categoria,
    p.estado,
    p.controlar_stock,
    c.nombre AS categoria_nombre,
    c.tipo_categoria AS categoria_tipo
  FROM productos p
    LEFT JOIN categorias_producto c
      ON p.id_categoria = c.id
  WHERE p.id = p_id;
END
$$

--
-- Create procedure `sp_getAllProducts`
--
CREATE

PROCEDURE sp_getAllProducts (IN p_id int,
IN p_nombre varchar(100),
IN p_descripcion text,
IN p_precio decimal(10, 2),
IN p_categoria_nombre varchar(100),
IN p_estado varchar(10),
IN p_controlar_stock boolean,
IN p_page_number int,
IN p_page_size int)
BEGIN
  DECLARE v_offset int;
  SET v_offset = (p_page_number - 1) * p_page_size;

  SELECT
    p.id,
    p.nombre,
    p.descripcion,
    p.precio,
    p.estado,
    p.controlar_stock,
    c.nombre AS categoria_nombre,
    c.tipo_categoria AS categoria_tipo
  FROM productos p
    LEFT JOIN categorias_producto c
      ON p.id_categoria = c.id
  WHERE (p_id IS NULL
  OR p.id = p_id)
  AND (p_nombre IS NULL
  OR p.nombre LIKE CONCAT('%', p_nombre, '%'))
  AND (p_descripcion IS NULL
  OR p.descripcion LIKE CONCAT('%', p_descripcion, '%'))
  AND (p_precio IS NULL
  OR p.precio = p_precio)
  AND (p_categoria_nombre IS NULL
  OR c.nombre = p_categoria_nombre)
  AND (p_estado IS NULL
  OR p.estado = p_estado)
  AND (p_controlar_stock IS NULL
  OR p.controlar_stock = p_controlar_stock)
  ORDER BY p.nombre
  LIMIT p_page_size OFFSET v_offset;
END
$$

