--
-- Create procedure `sp_createProduct`
--
CREATE

PROCEDURE sp_createProduct (IN p_nombre varchar(100),
IN p_descripcion text,
IN p_precio decimal(10, 2),
IN p_id_categoria int,
IN p_estado enum ('activo', 'inactivo'),
IN p_controlar_stock boolean)
BEGIN
  INSERT INTO productos (nombre, descripcion, precio, id_categoria, estado, controlar_stock)
    VALUES (p_nombre, p_descripcion, p_precio, p_id_categoria, p_estado, p_controlar_stock);
  SELECT
    LAST_INSERT_ID() AS id;
END
$$

--
-- Create procedure `sp_countAllProducts`
--
CREATE

PROCEDURE sp_countAllProducts (IN p_id int,
IN p_nombre varchar(100),
IN p_descripcion text,
IN p_precio decimal(10, 2),
IN p_categoria_nombre varchar(100),
IN p_estado varchar(10),
IN p_controlar_stock boolean)
BEGIN
  SELECT
    COUNT(*) AS total_records
  FROM productos p
    LEFT JOIN categorias_producto c
      ON p.id_categoria = c.id
  WHERE (p_id IS NULL
  OR p.id = p_id)
  AND (p_nombre IS NULL
  OR p.nombre LIKE CONCAT('%', p_nombre, '%'))
  AND (p_descripcion IS NULL
  OR p.descripcion LIKE CONCAT('%', p_descripcion, '%'))
  AND (p_precio IS NULL
  OR p.precio = p_precio)
  AND (p_categoria_nombre IS NULL
  OR c.nombre = p_categoria_nombre)
  AND (p_estado IS NULL
  OR p.estado = p_estado)
  AND (p_controlar_stock IS NULL
  OR p.controlar_stock = p_controlar_stock);
END
$$

