DELIMITER $$

--
-- Create procedure `sp_update_movimiento`
--
CREATE

PROCEDURE sp_update_movimiento (IN p_id_movimiento bigint,
IN p_anio char(4),
IN p_periodo char(2),
IN p_codigo_movimiento int,
IN p_fecha_movimiento date,
IN p_id_tipo_documento_venta int,
IN p_serie_documento varchar(10),
IN p_numero_documento varchar(20),
IN p_tipo_entidad enum ('C', 'P'),
IN p_id_cliente int,
IN p_id_proveedor int,
IN p_estado enum ('Activado', 'Desactivado'),
IN p_detalle json,
IN p_id_almacen char(1))
BEGIN
  DECLARE v_tipo_movimiento_char char(1);
  DECLARE v_index int DEFAULT 0;
  DECLARE v_item_count int;

  SELECT
    tipo INTO v_tipo_movimiento_char
  FROM tipo_movimiento
  WHERE id = p_codigo_movimiento;

  START TRANSACTION;

    UPDATE movimientos
    SET anio = p_anio,
        periodo = p_periodo,
        tipo_movimiento = v_tipo_movimiento_char,
        codigo_movimiento = p_codigo_movimiento,
        fecha_movimiento = p_fecha_movimiento,
        id_tipo_documento_venta = p_id_tipo_documento_venta,
        serie_documento = p_serie_documento,
        numero_documento = p_numero_documento,
        tipo_entidad = p_tipo_entidad,
        id_cliente = p_id_cliente,
        id_proveedor = p_id_proveedor,
        estado = p_estado,
        id_almacen = p_id_almacen
    WHERE id = p_id_movimiento;

    DELETE
      FROM movimientos_detalle
    WHERE id_movimiento = p_id_movimiento;

    SET v_item_count = JSON_LENGTH(p_detalle);
    WHILE v_index < v_item_count DO
      INSERT INTO movimientos_detalle (id_movimiento, item, id_producto, cantidad, descripcion, codigo_unidad_medida, costo_unitario, costo_neto)
        VALUES (p_id_movimiento, JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].item'))), JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].id_producto'))), JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].cantidad'))), JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].descripcion'))), JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].codigo_unidad_medida'))), JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].costo_unitario'))), JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].cantidad'))) * JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].costo_unitario'))));
      SET v_index = v_index + 1;
    END WHILE;

  COMMIT;
END
$$

--
-- Create procedure `sp_get_movimiento_by_id`
--
CREATE

PROCEDURE sp_get_movimiento_by_id (IN p_id bigint)
BEGIN
  -- Obtener cabecera
  SELECT
    m.*,
    tm.descripcion AS nombre_movimiento,
    a.nombre AS nombre_almacen
  FROM movimientos m
    JOIN tipo_movimiento tm
      ON m.codigo_movimiento = tm.id

    JOIN almacenes a
      ON m.id_almacen = a.id

  WHERE m.id = p_id;

  -- Obtener detalle
  SELECT
    md.*,
    p.nombre AS nombre_producto
  FROM movimientos_detalle md
    JOIN productos p
      ON md.id_producto = p.id
  WHERE md.id_movimiento = p_id
  ORDER BY md.item;
END
$$

--
-- Create procedure `sp_create_movimiento`
--
CREATE

PROCEDURE sp_create_movimiento (IN p_anio char(4),
IN p_periodo char(2),
IN p_codigo_movimiento int,
IN p_fecha_movimiento date,
IN p_id_tipo_documento_venta int,
IN p_serie_documento varchar(10),
IN p_numero_documento varchar(20),
IN p_tipo_entidad enum ('C', 'P'),
IN p_id_cliente int,
IN p_id_proveedor int,
IN p_detalle json,
IN p_id_almacen int)
BEGIN
  DECLARE v_id_movimiento bigint;
  DECLARE v_tipo_movimiento_char char(1);
  DECLARE v_index int DEFAULT 0;
  DECLARE v_item_count int;
  DECLARE v_item int;
  DECLARE v_id_producto int;
  DECLARE v_cantidad decimal(14, 5);
  DECLARE v_descripcion text;
  DECLARE v_codigo_unidad_medida varchar(3);
  DECLARE v_costo_unitario decimal(14, 5);


  SELECT
    tipo INTO v_tipo_movimiento_char
  FROM tipo_movimiento
  WHERE id = p_codigo_movimiento;

  START TRANSACTION;

    INSERT INTO movimientos (anio, periodo, tipo_movimiento, codigo_movimiento, fecha_movimiento, id_tipo_documento_venta, serie_documento, numero_documento, tipo_entidad, id_cliente, id_proveedor, estado, id_almacen)
      VALUES (p_anio, p_periodo, v_tipo_movimiento_char, p_codigo_movimiento, p_fecha_movimiento, p_id_tipo_documento_venta, p_serie_documento, p_numero_documento, p_tipo_entidad, p_id_cliente, p_id_proveedor, 'Activado', p_id_almacen);

    SET v_id_movimiento = LAST_INSERT_ID();
    SET v_item_count = JSON_LENGTH(p_detalle);

    WHILE v_index < v_item_count DO
      SET v_item = JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].item')));
      SET v_id_producto = JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].id_producto')));
      SET v_cantidad = JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].cantidad')));
      SET v_descripcion = JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].descripcion')));
      SET v_codigo_unidad_medida = JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].codigo_unidad_medida')));
      SET v_costo_unitario = JSON_UNQUOTE(JSON_EXTRACT(p_detalle, CONCAT('$[', v_index, '].costo_unitario')));

      INSERT INTO movimientos_detalle (id_movimiento, item, id_producto, cantidad, descripcion, codigo_unidad_medida, costo_unitario, costo_neto)
        VALUES (v_id_movimiento, v_item, v_id_producto, v_cantidad, v_descripcion, v_codigo_unidad_medida, v_costo_unitario, v_cantidad * v_costo_unitario);

      SET v_index = v_index + 1;
    END WHILE;

  COMMIT;
  SELECT
    v_id_movimiento AS id;
END
$$

DELIMITER ;

--
-- Create table `impuestos`
--
CREATE TABLE impuestos (
  id int(11) NOT NULL AUTO_INCREMENT,
  codigo char(3) NOT NULL,
  fecha_inicial date NOT NULL,
  fecha_final date DEFAULT NULL,
  valor decimal(10, 2) NOT NULL,
  estado tinyint(1) NOT NULL DEFAULT 1,
  fecha_creacion timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP(),
  fecha_actualizacion timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP() ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id)
)
ENGINE = INNODB,
AUTO_INCREMENT = 3,
AVG_ROW_LENGTH = 16384,
CHARACTER SET utf8mb4,
COLLATE utf8mb4_general_ci,
ROW_FORMAT = DYNAMIC;

DELIMITER $$

--
-- Create procedure `sp_leer_impuestos`
--
CREATE

PROCEDURE sp_leer_impuestos (IN p_codigo char(3),
IN p_estado boolean,
IN p_offset int,
IN p_limit int)
BEGIN
  SELECT
    id,
    codigo,
    fecha_inicial,
    fecha_final,
    valor,
    estado
  FROM `impuestos`
  WHERE (p_codigo IS NULL
  OR codigo = p_codigo)
  AND (p_estado IS NULL
  OR estado = p_estado)
  ORDER BY id DESC
  LIMIT p_offset, p_limit;
END
$$

--
-- Create procedure `sp_leer_impuesto_por_id`
--
CREATE

PROCEDURE sp_leer_impuesto_por_id (IN p_id int)
BEGIN
  SELECT
    id,
    codigo,
    fecha_inicial,
    fecha_final,
    valor,
    estado
  FROM `impuestos`
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_leer_codigos_impuesto`
--
CREATE

PROCEDURE sp_leer_codigos_impuesto ()
BEGIN
  SELECT DISTINCT
    codigo
  FROM `impuestos`
  ORDER BY codigo ASC;
END
$$

--
-- Create procedure `sp_eliminar_impuesto`
--
CREATE

PROCEDURE sp_eliminar_impuesto (IN p_id int)
BEGIN
  DELETE
    FROM `impuestos`
  WHERE id = p_id;
END
$$

--
-- Create procedure `sp_crear_impuesto`
--
CREATE

PROCEDURE sp_crear_impuesto (IN p_codigo char(3),
IN p_fecha_inicial date,
IN p_fecha_final date,
IN p_valor decimal(10, 2),
IN p_estado boolean)
BEGIN
  INSERT INTO `impuestos` (codigo, fecha_inicial, fecha_final, valor, estado)
    VALUES (p_codigo, p_fecha_inicial, p_fecha_final, p_valor, p_estado);
END
$$

--
-- Create procedure `sp_contar_impuestos`
--
CREATE

PROCEDURE sp_contar_impuestos (IN p_codigo char(3),
IN p_estado boolean)
BEGIN
  SELECT
    COUNT(id) AS total
  FROM `impuestos`
  WHERE (p_codigo IS NULL
  OR p_codigo = ''
  OR codigo = p_codigo)
  AND (p_estado IS NULL
  OR estado = p_estado);
END
$$

--
-- Create procedure `sp_calcular_y_actualizar_impuestos_venta`
--
CREATE

PROCEDURE sp_calcular_y_actualizar_impuestos_venta (IN p_id_venta int)
BEGIN
  -- Declaración de variables para almacenar los valores calculados
  DECLARE v_total decimal(10, 2);
  DECLARE v_porcentaje decimal(10, 2);
  DECLARE v_base decimal(10, 2);
  DECLARE v_impuesto decimal(10, 2);

  -- 1. Obtener el total de la venta
  SELECT
    total INTO v_total
  FROM ventas
  WHERE id = p_id_venta;

  -- 2. Obtener el porcentaje de impuesto aplicable
  -- Se busca el impuesto activo más reciente según la fecha actual.
  -- Un impuesto está activo si la fecha actual está entre la fecha inicial y final,
  -- o si la fecha final es nula y la fecha actual es posterior a la inicial.
  SELECT
    valor INTO v_porcentaje
  FROM impuestos
  WHERE (NOW() BETWEEN fecha_inicial AND fecha_final)
  OR (fecha_final IS NULL
  AND NOW() >= fecha_inicial)
  ORDER BY id DESC
  LIMIT 1;

  -- Si no se encuentra un impuesto aplicable, se puede establecer un valor por defecto o manejar el error.
  -- Por ahora, si no se encuentra, el porcentaje será NULL y los cálculos también.
  IF v_porcentaje IS NOT NULL
    AND v_total > 0 THEN
    -- 3. Calcular la base imponible
    -- Fórmula: base = total / (1 + (porcentaje / 100))
    SET v_base = v_total / (1 + (v_porcentaje / 100));

    -- 4. Calcular el monto del impuesto
    -- Fórmula: impuesto = total - base
    SET v_impuesto = v_total - v_base;
  ELSE
    -- Si no hay porcentaje o total, los valores se establecen en NULL o 0.
    SET v_base = v_total; -- O NULL si se prefiere
    SET v_impuesto = 0.00; -- O NULL
  END IF;

  -- 5. Actualizar la tabla de ventas con los nuevos valores
  UPDATE ventas
  SET porcentaje = v_porcentaje,
      base = v_base,
      impuesto = v_impuesto
  WHERE id = p_id_venta;

END
$$

--
-- Create procedure `sp_update_venta`
--
CREATE

PROCEDURE sp_update_venta (IN p_id_venta int,
IN p_fecha_emision datetime)
BEGIN
  -- Iniciar transacción para asegurar la atomicidad de la operación
  START TRANSACTION;

    -- 1. Actualizar la fecha de emisión de la venta.
    --    Actualmente, es el único campo editable desde el formulario.
    UPDATE ventas
    SET fecha_emision = p_fecha_emision
    WHERE id = p_id_venta;

    -- 2. Llamar al procedimiento de cálculo de impuestos.
    --    Esto asegura que si el impuesto aplicable ha cambiado con el tiempo,
    --    los valores se actualicen de acuerdo a la nueva fecha de emisión.
    CALL sp_calcular_y_actualizar_impuestos_venta(p_id_venta);

  -- Confirmar la transacción
  COMMIT;

END
$$

--
-- Create procedure `sp_crear_venta_con_impuestos`
--
CREATE

PROCEDURE sp_crear_venta_con_impuestos (IN p_id_pedido int,
IN p_id_cliente int,
IN p_id_usuario_cajero int,
IN p_id_tipo_documento_venta int,
IN p_id_serie_documento int)
BEGIN
  -- Declaración de variables
  DECLARE v_id_venta int;
  DECLARE v_total_pedido decimal(10, 2);
  DECLARE v_numero_documento varchar(20);

  -- Iniciar transacción para asegurar la atomicidad
  START TRANSACTION;

    -- 1. Obtener el total del pedido
    SELECT
      total INTO v_total_pedido
    FROM pedidos
    WHERE id = p_id_pedido;

    -- 2. Obtener el siguiente número de documento para la serie
    SELECT
      LPAD(IFNULL(MAX(CAST(numero_documento AS UNSIGNED)), 0) + 1, 8, '0') INTO v_numero_documento
    FROM ventas
    WHERE id_serie_documento = p_id_serie_documento;

    -- 3. Crear la cabecera de la venta
    INSERT INTO ventas (id_pedido, id_cliente, id_usuario_cajero, id_tipo_documento_venta,
    id_serie_documento, numero_documento, total, fecha_emision)
      VALUES (
      p_id_pedido, p_id_cliente, p_id_usuario_cajero, p_id_tipo_documento_venta,
      p_id_serie_documento, v_numero_documento, v_total_pedido, NOW()
      );
    SET v_id_venta = LAST_INSERT_ID();

    -- 4. Copiar el detalle del pedido al detalle de la venta
    INSERT INTO venta_detalle (id_venta, id_producto, cantidad, precio_unitario)
      SELECT
        v_id_venta,
        id_producto,
        cantidad,
        precio_unitario
      FROM detalle_pedidos
      WHERE id_pedido = p_id_pedido;

    -- 5. Actualizar el estado del pedido a 'pagado'
    UPDATE pedidos
    SET estado = 'pagado'
    WHERE id = p_id_pedido;

    -- 6. Calcular y actualizar los impuestos para la nueva venta
    CALL sp_calcular_y_actualizar_impuestos_venta(v_id_venta);

  -- Confirmar la transacción
  COMMIT;

  -- 7. Devolver el ID de la venta y el número de documento generado
  SELECT
    v_id_venta AS id_venta,
    v_numero_documento AS numero_documento;

END
$$

--
-- Create procedure `sp_actualizar_impuesto`
--
CREATE

PROCEDURE sp_actualizar_impuesto (IN p_id int,
IN p_codigo char(3),
IN p_fecha_inicial date,
IN p_fecha_final date,
IN p_valor decimal(10, 2),
IN p_estado boolean)
BEGIN
  UPDATE `impuestos`
  SET codigo = p_codigo,
      fecha_inicial = p_fecha_inicial,
      fecha_final = p_fecha_final,
      valor = p_valor,
      estado = p_estado
  WHERE id = p_id;
END
$$

DELIMITER ;

